{
    "level": "A1–A2",
    "intro": "In this topic you will learn <strong>question forms</strong> (question forms) in the English language - the main types of interrogative sentences and the rules for their construction.",
    "rules": [
        {
            "label": "YES/NO QUESTIONS",
            "color": "emerald",
            "text": "<strong>General questions</strong> - answer "yes" or "no":",
            "example": "Do you like tea? Are you ready? Can you help?"
        },
        {
            "label": "WH-QUESTIONS",
            "color": "blue",
            "text": "<strong>Special questions</strong> — begin with a question word:",
            "example": "What do you want? Where are you going? Why is she here?"
        },
        {
            "label": "WORD ORDER",
            "color": "amber",
            "text": "<strong>Inversion</strong> is an auxiliary verb before the subject:",
            "example": "Auxiliary + Subject + Main Verb"
        }
    ]
}

{
    "title": "1. What are question forms?",
    "intro": "There are different ways to ask questions in English:",
    "items": [
        {
            "label": "Yes/No",
            "title": "General questions",
            "subtitle": "A yes or no answer — Do you...? Is she...?"
        },
        {
            "label": "Wh-Questions",
            "title": "Special questions",
            "subtitle": "Start with what, where, when, why, who, how"
        },
        {
            "label": "Alternative",
            "title": "Alternative questions",
            "subtitle": "Choose between options — Tea or coffee?"
        },
        {
            "label": "Tag",
            "title": "Chapter questions",
            "subtitle": "Questions at the end of the sentence — You like it, don't you?"
        },
        {
            "label": "Subject",
            "title": "Question to the subject",
            "subtitle": "Who/What as a subject — Who came? What happened?"
        },
        {
            "label": "Indirect",
            "title": "Indirect questions",
            "subtitle": "More polite forms — Can you tell me where...?"
        }
    ]
}

{
    "title": "2. Basic word order in questions",
    "sections": [
        {
            "label": "Subject and verb inversion",
            "color": "emerald",
            "description": "In questions <strong>the auxiliary verb is placed before the subject</strong>. This is called an inversion.",
            "examples": [
                {
                    "en": "You are ready. → Are you ready?",
                    "ua": "Are you ready? (inversion of are and you)"
                },
                {
                    "en": "She can swim. → Can she swim?",
                    "ua": "She can swim? (inversion of can and she)"
                },
                {
                    "en": "They will come. → Will they come?",
                    "ua": " (inversion of will and they)"
                }
            ]
        },
        {
            "label": "General question formula",
            "color": "blue",
            "description": "Basic question structure in English:",
            "examples": [
                {
                    "en": "Auxiliary + Subject + Main Verb + ...?",
                    "ua": "Auxiliary + Subject + Main Verb + ...?"
                },
                {
                    "en": "Do you speak English?",
                    "ua": "Do you speak English?"
                },
                {
                    "en": "Is he coming tonight?",
                    "ua": "He will come tonight?"
                }
            ],
            "note": "📌 The auxiliary verb always precedes the subject in questions!"
        }
    ]
}

{
    "title": "3. Yes/No Questions — General questions",
    "sections": [
        {
            "label": "With DO/DOES/DID",
            "color": "emerald",
            "description": "In simple tenses (Simple) we use <strong>do/does/did</strong> to form questions.",
            "examples": [
                {
                    "en": "Do you like coffee?",
                    "ua": "Do you like coffee?"
                },
                {
                    "en": "Does she work here?",
                    "ua": "Does she work here?"
                },
                {
                    "en": "Did they arrive on time?",
                    "ua": "They arrived on time?"
                }
            ]
        },
        {
            "label": "With TO BE",
            "color": "sky",
            "description": "With the verb <strong>to be</strong> we make an inversion - we put be before the subject.",
            "examples": [
                {
                    "en": "Are you Ready? <strong>modal verbs</strong> (can, will, should, must, may) make an inversion.",
                    "ua": "Ти готовий?"
                },
                {
                    "en": "Is she at home?",
                    "ua": "Вона вдома?"
                },
                {
                    "en": "Were they happy?",
                    "ua": "Вони були щасливі?"
                }
            ]
        },
        {
            "label": "З модальними дієсловами",
            "color": "purple",
            "description": "З <strong>модальними дієсловами</strong> (can, will, should, must, may) робимо інверсію.",
            "examples": [
                {
                    "en": "Can you swim?",
                    "ua": "Do you know how to swim?"
                },
                {
                    "en": "Will she come?",
                    "ua": "She will come?"
                },
                {
                    "en": "Should we wait?",
                    "ua": "Should we wait?"
                }
            ]
        }
    ]
}

{
    "title": "4. Wh-Questions - Special questions",
    "sections": [
        {
            "label": "Question Words)",
            "color": "emerald",
            "description": "Special questions start with a <strong>question word</strong>:",
            "examples": [
                {
                    "en": "What? ",
                    "ua": "What do you want? - What do you want? "
                },
                {
                    "en": "Where - Where? Kudi?",
                    "ua": "Where are you going? - Where are you going?"
                },
                {
                    "en": "When - Koli?",
                    "ua": "When did they arrive? - When did they arrive?"
                },
                {
                    "en": "Why - Why?",
                    "ua": "Why is she crying? - Why is she crying?"
                },
                {
                    "en": "Who - Who?",
                    "ua": "Who called you? - Who called you?"
                },
                {
                    "en": "How - How?",
                    "ua": "How do you know? — How do you know?"
                }
            ]
        },
        {
            "label": "Wh-question structure",
            "color": "blue",
            "description": "Special question formula:",
            "examples": [
                {
                    "en": "Wh-word + Auxiliary + Subject + Main Verb?",
                    "ua": "Interrogative word + Auxiliary + Subject + Verb?"
                },
                {
                    "en": "What do you want?",
                    "ua": "What do you want?[[[CODX_4]]]Where is she going? she leaves?"
                },
                {
                    "en": "Where is she going?",
                    "ua": "Куди вона йде?"
                },
                {
                    "en": "Why did they leave?",
                    "ua": "Why did they leave?"
                }
            ]
        },
        {
            "label": "Subject Questions",
            "color": "amber",
            "description": "When <strong>Who/What is the subject</strong>, the word order is as in an affirmative sentence (without do/does/did):",
            "examples": [
                {
                    "en": "Who called you?",
                    "ua": "Who called you? (Who is the subject)"
                },
                {
                    "en": "What happened?",
                    "ua": "What happened? (What is the subject)"
                },
                {
                    "en": "Who knows the answer?",
                    "ua": "Who knows the answer?"
                }
            ],
            "note": "📌 If Who/What is the subject, do not add do/does/did!"
        }
    ]
}

{
    "title": "5. Auxiliary verbs in questions",
    "sections": [
        {
            "label": "DO/DOES/DID - for Simple Tenses",
            "color": "emerald",
            "description": "In simple tenses (Present Simple, Past Simple) we use do/does/did as auxiliary:",
            "examples": [
                {
                    "en": "Present Simple: Do/Does",
                    "ua": "Do you live here? Does she work?"
                },
                {
                    "en": "Past Simple: Did",
                    "ua": "Did they go? Did you see? am/is/are"
                }
            ],
            "note": "📌 Основне дієслово у базовій формі (без -s, -ed)!"
        },
        {
            "label": "TO BE — інверсія",
            "color": "sky",
            "description": "З дієсловом <strong>to be</strong> не потрібен do/does/did — просто робимо інверсію:",
            "examples": [
                {
                    "en": "Present: am/is/are",
                    "ua": "Are you ready? Is she here?"
                },
                {
                    "en": "Past: was/were",
                    "ua": "Was he there? Were they happy?"
                }
            ]
        },
        {
            "label": "HAVE/HAS is for Perfect Tenses",
            "color": "purple",
            "description": "In the perfect tenses (Present Perfect, Past Perfect) have/has is an auxiliary verb:",
            "examples": [
                {
                    "en": "Present Perfect: have/has",
                    "ua": "Have you seen this? Has she finished?"
                },
                {
                    "en": "past perfect: had Could",
                    "ua": "Had they left before you arrived?"
                }
            ]
        },
        {
            "label": "Модальні дієслова — інверсія",
            "color": "amber",
            "description": "Модальні дієслова (can, will, should, must, may, might) виносяться перед підмет:",
            "examples": [
                {
                    "en": "Can, Could",
                    "ua": "Can you help? Could she come?"
                },
                {
                    "en": "Will, Would",
                    "ua": "Will they arrive? Would you like tea?"
                },
                {
                    "en": "Should, Must, May",
                    "ua": "Should I wait? Must we go? May I ask?"
                }
            ]
        }
    ]
}

{
    "title": "6. Questions in different tenses",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "We use <strong>do/does</strong> (with to be — inversion of am/is/are):",
            "examples": [
                {
                    "en": "Do you speak English?",
                    "ua": "Do you speak English?"
                },
                {
                    "en": "Does she live Here? now?" Simple",
                    "ua": "Вона тут живе?"
                },
                {
                    "en": "Are you a student?",
                    "ua": "Ти студент?"
                }
            ]
        },
        {
            "label": "Present Continuous",
            "color": "sky",
            "description": "Інверсія <strong>am/is/are</strong>:",
            "examples": [
                {
                    "en": "Are you working now?",
                    "ua": "Ти зараз працюєш?"
                },
                {
                    "en": "Is she coming?",
                    "ua": "Вона йде (приходить)?"
                },
                {
                    "en": "What are they doing?",
                    "ua": "Що вони роблять?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "purple",
            "description": "We use <strong>did</strong> (with to be — the inversion of was/were):",
            "examples": [
                {
                    "en": "Did you see the movie? left?",
                    "ua": "Ти бачив цей фільм?"
                },
                {
                    "en": "Where did she go?",
                    "ua": "Куди вона пішла?"
                },
                {
                    "en": "Were you at home?",
                    "ua": "You were at home?"
                }
            ]
        },
        {
            "label": "Present Perfect",
            "color": "amber",
            "description": "Inversion <strong>have/has</strong>:",
            "examples": [
                {
                    "en": "Have you ever been to Paris?",
                    "ua": "Have you ever been to Paris?"
                },
                {
                    "en": "Has she finished her work?",
                    "ua": " What have they done? "
                },
                {
                    "en": "What have they done? Party? Comparison of question types",
                    "ua": "Що вони зробили?"
                }
            ]
        },
        {
            "label": "Future Simple",
            "color": "rose",
            "description": "Інверсія <strong>will</strong>:",
            "examples": [
                {
                    "en": "Will you come to the party?",
                    "ua": "Ти прийдеш на вечірку?"
                },
                {
                    "en": "When will she arrive?",
                    "ua": "Коли вона приїде?"
                },
                {
                    "en": "What will they do?",
                    "ua": "Що вони робитимуть?"
                }
            ]
        }
    ]
}

{
    "title": "7. Порівняння типів питань",
    "intro": "Different types of interrogative sentences in English:",
    "rows": [
        {
            "en": "Yes/No Questions",
            "ua": "General questions",
            "note": "Do you like tea? — Yes/No"
        },
        {
            "en": "Wh-Questions",
            "ua": "Special questions",
            "note": "What do you want? — Specific information"
        },
        {
            "en": "Subject Questions",
            "ua": "Subject Questions",
            "note": "Who called? — No do/does/did needed"
        },
        {
            "en": "Alternative Questions",
            "ua": "Alternative questions",
            "note": "Tea or coffee? — Choice between options"
        },
        {
            "en": "Tag Questions",
            "ua": "Sectional questions",
            "note": "You like it, don't you? — Confirmation"
        },
        {
            "en": "Indirect Questions",
            "ua": "Indirect questions",
            "note": "Can you tell me where...? — More polite"
        }
    ],
    "warning": "📌 Each type of question has its own specific structure!"
}

{
    "title": "8. When to use do/does/did",
    "intro": "Rules for using auxiliary verbs do/does/did:",
    "rows": [
        {
            "en": "Simple Tenses (main verbs)",
            "ua": "With main verbs",
            "note": "Do you work? Does she know? Did they go?"
        },
        {
            "en": "NOT with TO BE",
            "ua": "NOT with to be",
            "note": "❌ Do you are happy? ✅ Are you happy?"
        },
        {
            "en": "NOT with modals",
            "ua": "NOT with modals",
            "note": "❌ Do you can swim? ✅ Can you swim?"
        },
        {
            "en": "NOT with have (perfect)",
            "ua": "NOT with have (perfect)",
            "note": "❌ Do you have seen? ✅ Have you seen?"
        },
        {
            "en": "NOT in subject questions",
            "ua": "NOT in subject questions",
            "note": "❌ Who did call? ✅ Who called?"
        }
    ],
    "warning": "⚠️ Do/Does/Did are ONLY used with main verbs in Simple Tenses!"
}

{
    "title": "9. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Incorrect word order - subject before auxiliary verb.",
            "wrong": "❌ You are happy? She can swim?",
            "right": " ✅ <span class="font-mono">Are you happy? Can she swim?</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Using do/does/did with to be.",
            "wrong": "❌ Do you are ready? Did you were there?",
            "right": "​​​​​​ Were you there?</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Using do/does/did with modal verbs.",
            "wrong": "❌ Do you can help? Did she come? ",
            "right": " ✅ <span class="font-mono">Can you help? Could she come?</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Incorrect form of the main verb.",
            "wrong": "❌ Does she works? Did they go?",
            "right": " ✅ <span class="font-mono">Does she work? Did they go?</span>"
        },
        {
            "label": "Error 5",
            "color": "emerald",
            "title": "Adding do/does/did in questions to the subject.",
            "wrong": "❌ Who did call you? What did happen?",
            "right": "​​​​ <span class="font-mono">Who called you? What happened?</span>"
        },
        {
            "label": "Error 6",
            "color": "indigo",
            "title": "Omission of auxiliary verb.",
            "wrong": "❌ You like coffee? She speaks English?",
            "right": "​​​​ <span class="font-mono">Do you like coffee? Does she speak English?</span>"
        }
    ]
}

{
    "title": "11. Practice",
    "select_title": "Exercise 1. Choose the correct option",
    "select_intro": "Choose the correct form of the question.",
    "selects": [
        {
            "label": "a) Do you are happy? / b) Are you happy? / c) Are you happy?",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) Where does she live? / b) Where does she live? / c) Where does she live?",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) Can you help me? / b) Can you help me? / c) You can help me?",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) Who did call? / b) Who called? / c) Who does calling? French. → ",
            "prompt": "Який варіант правильний?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Вправа 2. Постав питання",
    "input_intro": "Утвори питання з поданого речення.",
    "inputs": [
        {
            "before": "She speaks French. → ",
            "after": ""
        },
        {
            "before": "They are students. → ",
            "after": ""
        },
        {
            "before": "He can drive. → ",
            "after": ""
        },
        {
            "before": "You went to Paris. (Where...?) → ",
            "after": ""
        }
    ],
    "rephrase_title": "Exercise 3. Correct the error",
    "rephrase_intro": "Find and correct the error in the question.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "You are ready?",
            "example_target": "Are you ready?"
        },
        {
            "original": "1. Do you are happy?",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. Where she lives?",
            "placeholder": "Fix the error"
        },
        {
            "original": "3. Do you can swim?",
            "placeholder": "Fix the error"
        },
        {
            "original": "4. Who did call you?",
            "placeholder": "Correction"
        }
    ]
}

